#include <bits/stdc++.h>
using namespace std;

struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {}
};

class Solution {
public:
    ListNode* getIntersectionNode(ListNode* headA, ListNode* headB) {
        unordered_set<int> seen;
        for (ListNode* cur = headA; cur; cur = cur->next) {
            seen.insert(cur->val);
        }
        for (ListNode* cur = headB; cur; cur = cur->next) {
            if (seen.count(cur->val)) return cur;
        }
        return nullptr;
    }
};

ListNode* buildList(const vector<int>& vals) {
    ListNode dummy(0);
    ListNode* cur = &dummy;
    for (int v : vals) {
        cur->next = new ListNode(v);
        cur = cur->next;
    }
    return dummy.next;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n1;
    if (!(cin >> n1)) return 0;
    vector<int> a(n1);
    for (int i = 0; i < n1; ++i) cin >> a[i];
    int n2;
    cin >> n2;
    vector<int> b(n2);
    for (int i = 0; i < n2; ++i) cin >> b[i];
    ListNode* headA = buildList(a);
    ListNode* headB = buildList(b);
    Solution sol;
    ListNode* inter = sol.getIntersectionNode(headA, headB);
    if (inter) cout << inter->val << "\n";
    else cout << -1 << "\n";
    return 0;
}
